import py4godot.utils.functools as  functools
import py4godot.utils.utils as utils
from py4godot.classes.core import *
from py4godot.utils.smart_cast import smart_cast, register_cast_function, register_class, get_class
from py4godot.utils.CPPWrapper import CPPWrapper, constructor, static_method
import py4godot.utils.utils as c_utils
from py4godot.utils.CoreType import CoreType
import typing
import py4godot.variant_types
import py4godot.classes as classes
import py4godot.classes as classes
import py4godot.signals as signals

import typing
if typing.TYPE_CHECKING:
  pass
  import py4godot.classes.StreamPeerUDS as py4godot_streampeeruds 
import py4godot.classes.SocketServer as py4godot_socketserver 
from py4godot.wrappers.wrappers import CPPUDSServerWrapper


class UDSServer(py4godot_socketserver.SocketServer):
  r'''
		A Unix Domain Socket (UDS) server. Listens to connections on a socket path and returns a `StreamPeerUDS` when it gets an incoming connection. Unix Domain Sockets provide inter-process communication on the same machine using the filesystem namespace.
		**Note:** Unix Domain Sockets are only available on Unix-like systems (Linux, macOS, etc.) and are not supported on Windows.
	'''

  @staticmethod
  def constructor():
    class_ = UDSServer.construct_without_init()
    class_._ptr = constructor(911,0, ())
    return class_
  @staticmethod
  def new():
    class_ = UDSServer.construct_without_init()
    class_._ptr = constructor(911,0, ())
    return class_
  def __init__(self):
    self._ptr =  CPPUDSServerWrapper()
    self.casted_from = None
    if c_utils.shouldCreateObject:
      self._ptr = constructor(911,0, ())


  def generate_wrapper(self):
    return CPPUDSServerWrapper()
  def init_signals(self):
    super().init_signals()

  @staticmethod
  def construct_without_init():
    cls = UDSServer.__new__(UDSServer)
    cls.shouldBeDeleted = True
    cls.casted_from = None
    cls.constructed_from_python = False
    cls.init_signals()
    return cls
  @staticmethod
  def get_type():
    return 'UDSServer'

  def __del__(self):
    if self.casted_from is None:
      self._ptr.call_with_return(59, ())
      self._ptr = None
  @staticmethod
  def cast(other:'Object'):
    assert other != None # Object to be casted must not be None
    cls = UDSServer.construct_without_init()
    cls._ptr = CPPUDSServerWrapper()
    cls._ptr_before = other._ptr # Save pointer
    cls._ptr.copy_gdowner(cls._ptr_before)
    cls.casted_from = other
    return cls
  @staticmethod
  def cast_without_reference(other: 'Object'):
    assert other != None # Object to be casted must not be None
    cls = UDSServer.construct_without_init()
    cls._ptr = CPPUDSServerWrapper()
    cls._ptr_before = other._ptr # Save pointer
    cls._ptr.copy_gdowner(cls._ptr_before)
    return cls

  @functools.native_method
  def listen(self, path:'str'   ) -> typing.Union[int]:
    r'''
				Listens on the socket at `path`. The socket file will be created at the specified path.
				**Note:** The socket file must not already exist at the specified path. You may need to remove any existing socket file before calling this method.
			'''

    assert(not path is None)
    assert isinstance(path, (str, String)), 'path must be str or String'





    assert(isinstance(path, (str, String)))
    py_string_path = path if isinstance(path, StringName) else c_utils.py_string_to_string(path)

    _ret:int
    _ret = self._ptr.call_with_return(57,tuple([py_string_path._ptr]))
    return _ret


  @functools.native_method
  def take_connection(self) -> typing.Union['py4godot_streampeeruds.StreamPeerUDS']:
    r'''
				If a connection is available, returns a StreamPeerUDS with the connection.
			'''




    _ret = classes.Object.Object.construct_without_init() #Smart casted to: StreamPeerUDS
    _ret._ptr = self._ptr.call_with_return(58,tuple([]))
    return smart_cast(_ret) if not _ret._ptr.is_null() else None



register_cast_function('UDSServer', UDSServer.cast)
register_class('UDSServer', UDSServer)
